Example conversation state management:
```typescript
class ConversationManager {
  private conversations = new Map<string, Conversation>();

  async handleMessage(userId: string, message: Message, channel: Channel): Promise<Response> {
    let conversation = this.conversations.get(userId) || this.createNewConversation(userId);

    // Update conversation context
    conversation.addMessage(message);

    // Determine language if not already set
    if (!conversation.language) {
      conversation.language = await this.languageDetector.detect(message.text);
    }

    // Process message through AI engine
    const aiResponse = await this.aiEngine.process({
      message: message.text,
      context: conversation.context,
      language: conversation.language,
      channel: channel
    });

    // Format response based on channel capabilities
    const formattedResponse = this.channelAdapter.format(aiResponse, channel);

    // Update conversation state
    conversation.updateContext(aiResponse);
    this.conversations.set(userId, conversation);

    return formattedResponse;
  }
}
```

