Example e-prescription workflow:
```typescript
class PrescriptionService {
  async createPrescription(consultationId: string, doctorId: string, medications: Medication[]): Promise<Prescription> {
    // Validate doctor credentials and permissions
    const doctor = await this.doctorRepository.findById(doctorId);
    if (!doctor.canPrescribe) {
      throw new Error('Doctor not authorized to prescribe');
    }

    // Check medication interactions
    const interactions = await this.medicationService.checkInteractions(medications);
    if (interactions.severity === 'high') {
      throw new Error(`Dangerous medication interaction: ${interactions.description}`);
    }

    // Create prescription record
    const prescription = new Prescription({
      consultationId,
      doctorId,
      medications,
      issuedAt: new Date(),
      expiresAt: new Date(Date.now() + 30 * 24 * 60 * 60 * 1000), // 30 days validity
      status: 'active'
    });

    // Generate digital signature
    prescription.signature = await this.signatureService.sign(prescription, doctor.digitalCertificate);

    // Generate unique verification code
    prescription.verificationCode = this.generateVerificationCode();

    // Store in database
    await this.prescriptionRepository.save(prescription);

    // Notify available pharmacies
    await this.pharmacyNotificationService.notifyNearbyPharmacies(prescription);

    return prescription;
  }
}
```

