Example scheduling implementation:
```typescript
class ConsultationScheduler {
  async findAvailableSlots(specialtyId: string, locationPreference: GeoPoint, dateRange: DateRange): Promise<AvailabilitySlot[]> {
    // Find providers matching criteria
    const providers = await this.providerRepository.findBySpecialty(specialtyId, locationPreference);

    // Get availability for each provider in date range
    const availabilityMap = new Map<string, AvailabilitySlot[]>();
    for (const provider of providers) {
      const availability = await this.availabilityService.getProviderAvailability(provider.id, dateRange);
      availabilityMap.set(provider.id, availability);
    }

    // Sort and filter slots based on provider rating and availability
    return this.rankAndFilterSlots(availabilityMap, providers);
  }

  async scheduleConsultation(userId: string, providerId: string, slotId: string): Promise<Consultation> {
    // Lock the slot to prevent double booking
    await this.availabilityService.lockSlot(slotId);

    try {
      // Verify slot is still available
      const slot = await this.availabilityService.getSlot(slotId);
      if (!slot.isAvailable) {
        throw new Error('Slot is no longer available');
      }

      // Create consultation record
      const consultation = new Consultation({
        userId,
        providerId,
        scheduledTime: slot.startTime,
        duration: slot.duration,
        status: 'scheduled',
        consultationType: 'video'
      });

      // Save consultation and update availability
      await this.consultationRepository.save(consultation);
      await this.availabilityService.markSlotBooked(slotId, consultation.id);

      // Send notifications
      await this.notificationService.notifyConsultationScheduled(consultation);

      return consultation;
    } catch (error) {
      // Release the lock if anything fails
      await this.availabilityService.unlockSlot(slotId);
      throw error;
    }
  }
}
```

