class EmergencyDetectionService {
  async analyzeUserInput(userId: string, input: string): Promise<EmergencyAssessment> {
    // Get user's medical history and risk factors
    const userProfile = await this.userProfileService.getProfile(userId);

    // Check for emergency keywords and phrases
    const keywordMatch = this.emergencyKeywordDetector.analyze(input, userProfile.language);

    // Get recent vital signs if available
    const recentVitals = await this.vitalSignsRepository.getRecent(userId, { minutes: 30 });

    // Perform comprehensive emergency assessment
    const assessment = this.emergencyAssessor.evaluate({
      textInput: input,
      keywordMatch,
      userProfile,
      vitalSigns: recentVitals
    });

    // If emergency detected, initiate response
    if (assessment.isEmergency) {
      await this.initiateEmergencyResponse(userId, assessment);
    }

    return assessment;
  }

  private async initiateEmergencyResponse(userId: string, assessment: EmergencyAssessment): Promise<void> {
    // Get user's current location
    const location = await this.locationService.getUserLocation(userId);

    // Determine appropriate emergency service based on location and condition
    const emergencyService = this.emergencyServiceRouter.determineService(location, assessment.condition);

    // Prepare medical information package for emergency responders
    const medicalPackage = await this.emergencyInfoGenerator.generatePackage(userId);

    // Contact emergency service
    await this.emergencyConnector.notifyService(emergencyService, {
      userId,
      location,
      assessment,
      medicalPackage
    });

    // Notify emergency contacts
    await this.notificationService.notifyEmergencyContacts(userId, assessment);

    // Log emergency event
    await this.emergencyLogger.logEmergency(userId, assessment, emergencyService);
  }
}
```

