Example subscription implementation:
```typescript
class SubscriptionService {
  async createSubscription(userId: string, planId: string, paymentMethod: PaymentMethod): Promise<Subscription> {
    // Get plan details
    const plan = await this.planRepository.findById(planId);
    if (!plan.isActive) {
      throw new Error('Selected plan is not currently available');
    }

    // Check if user already has an active subscription
    const existingSubscription = await this.subscriptionRepository.findActiveByUserId(userId);
    if (existingSubscription) {
      // Handle upgrade/downgrade/crossgrade logic
      return this.changeSubscription(existingSubscription.id, planId);
    }

    // Create payment method with payment processor
    const paymentToken = await this.paymentProcessor.registerPaymentMethod(userId, paymentMethod);

    // Calculate prorated amount if applicable
    const amount = this.calculateInitialPayment(plan);

    // Process initial payment
    const paymentResult = await this.paymentProcessor.processPayment({
      userId,
      paymentToken,
      amount,
      description: `Initial payment for ${plan.name} subscription`
    });

    if (!paymentResult.success) {
      throw new Error(`Payment failed: ${paymentResult.errorMessage}`);
    }

    // Create subscription record
    const subscription = new Subscription({
      userId,
      planId,
      status: 'active',
      startDate: new Date(),
      currentPeriodEnd: this.calculatePeriodEnd(plan.billingInterval),
      paymentMethodId: paymentToken,
      lastPaymentDate: new Date(),
      lastPaymentAmount: amount
    });

    // Save subscription
    await this.subscriptionRepository.save(subscription);

    // Update user permissions based on plan
    await this.permissionService.updateUserPermissions(userId, plan.permissions);

    // Send confirmation
    await this.notificationService.sendSubscriptionConfirmation(subscription);

    return subscription;
  }
}
```
